-- 1) Add custody columns to stock_items
ALTER TABLE stock_items ADD COLUMN custody_type TEXT NOT NULL DEFAULT 'owned';
--   custody_type values:
--     'owned'                      = our stock, counted in inventory
--     'third_party_in_warehouse'   = held for client (Jester Sports, etc.)
--     'offsite'                    = our stock held elsewhere (POP Cape Town)
CREATE INDEX IF NOT EXISTS idx_stock_custody ON stock_items(custody_type);

-- 2) Clean slate (production was empty pre-seed; this is a safety net)
DELETE FROM stock_items;
DELETE FROM stock_aliases;
DELETE FROM stock_movements;

